class Solution:
    def numberOfSubarrays(self, nums: List[int]) -> int:
        n = len(nums)
        count = 0
        i = 0
        while i < n:
            j = i
            max_val = nums[i]
            while j < n and nums[j] <= max_val:
                if nums[j] == max_val:
                    count += 1
                j += 1
            i += 1
        return count
